// Source of truth for the SmartCaptions launch video copy: props/smartcaptions-launch.json
// is GENERATED by this script; edit copy here, never in the JSON (it gets clobbered).
// Telemetry is pulled from props/smartcaptions-demo.json so the demo act never drifts.
// Voice (brands/smartcaptions.json): editor-to-editor, plain and confident, no hype.
// Blue (#1667ff) is the brand; orange/amber are energy accents only. No em dashes.
//
// If out/smartcaptions/marketing/brief.json exists and validates, its COPY (headline,
// feature headings + lines, cta) overrides the hardcoded copy below; the
// assets/demo structure always stays local. With no valid brief the output is
// byte-identical to the pre-brief builder (mirrors scripts/build-dashclaw-launch-props.mjs).
import {readFileSync, existsSync, writeFileSync} from 'node:fs';
import {fileURLToPath} from 'node:url';
import {dirname, join} from 'node:path';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const demo = JSON.parse(readFileSync(join(root, 'props', 'smartcaptions-demo.json'), 'utf8'));

const launch = {
  brandId: 'smartcaptions',
  kicker: 'smartcaptions.co.il',
  headline: 'Captions for Premiere Pro, in one click',
  demo: {video: demo.video, telemetry: demo.telemetry},
  features: [
    {
      // Full panel at 9s: Transcribe In & Out / Transcribe Sequence buttons, all settings visible
      screenshot: 'smartcaptions/feature-1.png',
      heading: 'Transcribe inside the edit',
      lines: [
        'One click transcribes your whole sequence',
        'No exports, no uploads, no round trips',
        'Captions land straight on your timeline',
      ],
    },
    {
      // Cropped right column (820x513, 16:10): Translate toggle on + Speech/Text Auto Detect dropdowns
      screenshot: 'smartcaptions/feature-2.png',
      heading: 'Any language, translated on the way',
      lines: [
        'Auto-detects the spoken language',
        'Translate captions as they generate',
        'Hebrew and RTL handled properly',
      ],
    },
    {
      // Full panel at 16s: Editor & Timing Adjuster with caption cues, timecodes, Fix Words
      screenshot: 'smartcaptions/feature-3.png',
      heading: 'Word-level control',
      lines: [
        'Fix words and drag timings in the editor',
        'Fill Timeline closes every caption gap',
        'Max words per line fits your style',
      ],
    },
  ],
  cta: 'Try free at smartcaptions.co.il',
  assets: {
    logoSequence: 'smartcaptions/logo-reveal',
    logoFrames: 90,
    loopSequence: null,
    loopFrames: 1,
  },
};

// Overlay Content Brief copy when a valid brief exists. Structural checks below
// mirror studio/src/lib/brief.ts (the canonical zod schema, used by the studio +
// tests) — same convention scripts/build-dashclaw-launch-props.mjs uses.
// A missing or malformed brief falls through to the hardcoded copy untouched, so
// output is byte-identical with no brief present.
const briefPath = join(root, 'out', 'smartcaptions', 'marketing', 'brief.json');
if (existsSync(briefPath)) {
  const brief = validBrief(readFileSync(briefPath, 'utf8'));
  if (!brief) {
    console.warn('build-smartcaptions-launch-props: out/smartcaptions/marketing/brief.json is invalid; using hardcoded copy');
  } else {
    if (brief.hook.headline) launch.headline = brief.hook.headline;
    if (brief.cta) launch.cta = brief.cta;
    // Overlay copy by feature index; screenshots/structure stay local.
    brief.features.slice(0, launch.features.length).forEach((bf, i) => {
      if (bf.heading) launch.features[i].heading = bf.heading;
      if (bf.benefitLines.length) launch.features[i].lines = bf.benefitLines.slice(0, 3);
    });
  }
}

// Returns the parsed brief if it structurally matches brief.ts (only the copy
// fields this builder consumes are validated), otherwise null.
function validBrief(text) {
  let b;
  try {
    b = JSON.parse(text);
  } catch {
    return null;
  }
  if (!b || typeof b !== 'object') return null;
  if (typeof b.brandId !== 'string' || b.brandId.length === 0) return null;
  const hook = b.hook ?? {headline: '', altHeadlines: []};
  if (typeof hook.headline !== 'string') return null;
  const features = b.features ?? [];
  if (!Array.isArray(features)) return null;
  for (const f of features) {
    if (!f || typeof f.heading !== 'string') return null;
    if (!Array.isArray(f.benefitLines) || f.benefitLines.length > 3) return null;
    if (!f.benefitLines.every((l) => typeof l === 'string')) return null;
  }
  if (b.cta != null && typeof b.cta !== 'string') return null;
  return {hook, cta: typeof b.cta === 'string' ? b.cta : '', features};
}

writeFileSync(join(root, 'props', 'smartcaptions-launch.json'), JSON.stringify(launch, null, 2) + '\n');
console.log('wrote props/smartcaptions-launch.json');
